public static class UserRoleExtensions
{
    public static string GetDescription(this UserRole userRole)
    {
        return userRole switch
        {
            UserRole.Guest => "Unauthenticated user",
            UserRole.User => "Regular user",
            UserRole.Admin => "System administrator",
            _ => throw new ArgumentOutOfRangeException(nameof(userRole)),
        };
    }

    public static bool HasPermission(this UserRole userRole, Permission permission)
    {
        return userRole switch
        {
            UserRole.Admin => true,
            UserRole.User => permission == Permission.Read || permission == Permission.Write,
            _ => false,
        };
    }
}

public enum Permission
