**useNotificationContext.js**
```javascript
import { createContext, useContext, useState, useEffect } from 'react';
import { notify } from './notification.helpers';

interface NotificationContextInterface {
  notificationElem: HTMLHuelNotificationElement | null;
  notify: (props: Parameters<typeof notify>[1]) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextInterface>({
  notificationElem: null,
  notify: () => Promise.resolve(),
});

const useNotificationContext = () => {
  const [notificationElem, setNotificationElem] = useState<HTMLHuelNotificationElement | null>(null);
  const notifyContext = useContext(NotificationContext);

  useEffect(() => {
    if (!notificationElem) {
      const elem = document.querySelector('huel-notification');
      if (elem) {
        setNotificationElem(elem);
      }
    }
  }, [notificationElem]);

  const notify = async (props: Parameters<typeof notify>[1]) => {
    if (!notificationElem) return;

    await notifyContext.notify(notificationElem, props);
  };

  return { notificationElem, notify };
};

export { useNotificationContext, NotificationContext };
